SELECT count(*) FROM movie_companies, title, company_type, company_name, movie_keyword, keyword, cast_info, role_type, char_name WHERE movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND cast_info.person_role_id = char_name.id;